import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
  Transformer,
  Label,
  Tag,
  Text,
} from 'react-konva';
import './AnnotationCanvas.css';

// ----------------------------------------------------
// CLIPPING HELPERS
// ----------------------------------------------------

// We treat the image boundary as a rectangle [0,0 -> w,h]. We can clip any polygon
// against this boundary to get the "inside" portion plus any intersection points.
//
// This uses a standard Sutherland-Hodgman polygon clipping approach. For a bounding
// box, we convert it to a 4-vertex polygon, clip it, then store the result as a polygon
// (since after clipping, it may no longer be a perfect rectangle).
//
// For polylines, you can do a variant of polygon clipping if you want partial lines
// retained. Similarly, for ellipse or any shape, approximate them as polygons, clip
// the polygon, then store the result as a polygon. Below is a minimal polygon clipping
// approach; you can adapt it as needed.

function clipPolygonToRect(polygonPoints, width, height) {
  // polygonPoints is an array of { x, y }
  // We'll clip against the rectangle [0,0, width, height]
  // Return an array of { x, y } representing the clipped polygon
  // or an empty array if no inside region remains.

  const clipLeft = (points) => clipAgainstLine(points, 0, 0, 0, height);
  const clipRight = (points) => clipAgainstLine(points, width, 0, width, height);
  const clipTop = (points) => clipAgainstLine(points, 0, 0, width, 0);
  const clipBottom = (points) => clipAgainstLine(points, 0, height, width, height);

  // The order of clipping lines: left, right, top, bottom
  let output = polygonPoints;
  output = clipLeft(output);
  output = clipRight(output);
  output = clipTop(output);
  output = clipBottom(output);

  return output;
}

// Clip a polygon against a line (x1,y1 -> x2,y2). We keep the points "inside" the half-plane.
function clipAgainstLine(subjectPoints, x1, y1, x2, y2) {
  const clipped = [];
  for (let i = 0; i < subjectPoints.length; i++) {
    const curr = subjectPoints[i];
    const prev = subjectPoints[(i + subjectPoints.length - 1) % subjectPoints.length];

    const currInside = isInside(curr, x1, y1, x2, y2);
    const prevInside = isInside(prev, x1, y1, x2, y2);

    if (prevInside && currInside) {
      // both inside -> current point is added
      clipped.push(curr);
    } else if (prevInside && !currInside) {
      // leaving
      const inter = intersection(prev, curr, x1, y1, x2, y2);
      if (inter) clipped.push(inter);
    } else if (!prevInside && currInside) {
      // entering
      const inter = intersection(prev, curr, x1, y1, x2, y2);
      if (inter) clipped.push(inter);
      clipped.push(curr);
    } else {
      // both outside, do nothing
    }
  }
  return clipped;
}

// Check if point p is inside the half-plane to the "left" of the line (x1,y1 -> x2,y2)
function isInside(p, x1, y1, x2, y2) {
  // line normal approach
  // line from (x1,y1)->(x2,y2), a point is inside if cross(line, p - lineStart) >= 0
  // but each line is used to clip "inside" the rectangle
  // We'll interpret each edge carefully.
  // For the line (x1,y1)->(x2,y2), we want "the inside" to be on the left side of the direction
  // we define for that edge. We'll choose consistent directions for each rectangle boundary.
  // E.g., for left edge: line is top->bottom => inside is to the right => cross >= 0, etc.

  // We'll do the standard Sutherland-Hodgman approach: assume edges oriented CCW around the clip region.
  // Clip rectangle edges in sequence: left->top->right->bottom in CCW order,
  // or left->right->top->bottom with consistent orientation. The sign test will follow.

  // We can just do a 2D cross product sign approach:
  return (
    (x2 - x1) * (p.y - y1) - (y2 - y1) * (p.x - x1) >= 0
  );
}

// Intersection between segment p1->p2 and line x1,y1 -> x2,y2
function intersection(p1, p2, cx1, cy1, cx2, cy2) {
  // parametric approach
  // line segment p1->p2 param eq: p(t) = p1 + t*(p2-p1), t in [0,1]
  // clipping line cx1->cx2 param eq. We'll do standard line intersection formula

  const denom = (cy2 - cy1) * (p2.x - p1.x) - (cx2 - cx1) * (p2.y - p1.y);
  if (Math.abs(denom) < 1e-6) {
    return null; // parallel or nearly parallel
  }
  const ua = ((cx2 - cx1) * (p1.y - cy1) - (cy2 - cy1) * (p1.x - cx1)) / denom;
  const x = p1.x + ua * (p2.x - p1.x);
  const y = p1.y + ua * (p2.y - p1.y);
  return { x, y };
}

// Convert a bounding box to a 4-vertex polygon
function bboxToPolygon(bbox) {
  const { x, y, width, height } = bbox;
  return [
    { x, y },
    { x: x + width, y },
    { x: x + width, y: y + height },
    { x, y: y + height },
  ];
}

// Convert clipped polygon back to bounding box if it's still a proper rectangle. 
// If not, we just store it as a 'polygon' (including the intersection corners).
// For this sample, let's always store as 'polygon' if clipping happened.
function finalizeBboxClipping(bbox, clipped, imgWidth, imgHeight) {
  // If clipped is empty => shape is fully outside
  if (!clipped.length) return null;

  // If the clipped polygon has the same 4 corners (and is a rectangle),
  // we can store it back as a bounding box. If any difference, store as polygon.
  const originalPoly = bboxToPolygon(bbox);
  const same = samePolygon(originalPoly, clipped);
  if (same) {
    // no clipping needed
    return { ...bbox, x: bbox.x, y: bbox.y, width: bbox.width, height: bbox.height };
  } else {
    // store as polygon
    return { type: 'polygon', points: clipped, label: '' };
  }
}

// Check if two polygons have the same corners (order-insensitive check)
function samePolygon(polyA, polyB) {
  if (polyA.length !== polyB.length) return false;
  // A simple approach might try to rotate polyB to match polyA starting corner, etc.
  // For brevity, just do a quick approximate check ignoring order. This is enough to see if
  // no actual clipping changed anything. In real code, you'd do a robust check.
  const setA = new Set(polyA.map((p) => `${Math.round(p.x)}|${Math.round(p.y)}`));
  const setB = new Set(polyB.map((p) => `${Math.round(p.x)}|${Math.round(p.y)}`));
  if (setA.size !== setB.size) return false;
  for (let item of setA) {
    if (!setB.has(item)) return false;
  }
  return true;
}

// Clip any type of annotation to image boundary. If clipped region is empty => null
// Return either the same shape if fully inside, or a new shape (e.g. polygon) if partially clipped.
function clipAnnotationToImage(ann, imgWidth, imgHeight) {
  const w = imgWidth;
  const h = imgHeight;

  // For bounding box => convert to polygon -> clip -> convert back or store as polygon
  if (ann.type === 'bbox') {
    const poly = bboxToPolygon(ann);
    const clippedPoly = clipPolygonToRect(poly, w, h);
    return finalizeBboxClipping(ann, clippedPoly, w, h);
  }
  // For polygons => clip directly
  if (ann.type === 'polygon') {
    const clipped = clipPolygonToRect(ann.points, w, h);
    if (!clipped.length) return null;
    return { ...ann, points: clipped };
  }

  // For polylines or points, you can decide how you want them to be clipped.
  // - For polylines, you might want partial lines inside the boundary (a line clip).
  // - For multiple points, you'd just filter out points outside the boundary,
  //   and if any intersection is wanted, you'd do a line segment clip. That is more involved.
  // For simplicity, let's do a naive approach:
  //   - If polylines have any segment that goes outside, we clip that segment. We'll adapt the polygon approach
  //     but keep 'closed=false'. This is up to you how you want to treat partial polylines.

  if (ann.type === 'polyline') {
    // treat as polygon but not closed, then store the resulting shape as a polyline
    // for proper line clipping, you can do a specialized algorithm. We'll do a simple approach:
    const clipped = clipPolylineToRect(ann.points, w, h);
    if (clipped.length < 2) return null;
    return { ...ann, points: clipped };
  }

  if (ann.type === 'points') {
    // remove points outside boundary
    const insidePoints = ann.points.filter(
      (p) => p.x >= 0 && p.x <= w && p.y >= 0 && p.y <= h
    );
    if (!insidePoints.length) return null;
    return { ...ann, points: insidePoints };
  }

  // For a single point, see if it's inside. If outside => null
  if (ann.type === 'point') {
    if (
      ann.x < 0 ||
      ann.x > w ||
      ann.y < 0 ||
      ann.y > h
    ) {
      return null;
    }
    return ann;
  }

  // For ellipse, a precise approach would do an ellipse-rectangle clipping and produce a polygon of intersection.
  // Let's do a quick approach: approximate ellipse with N points, clip it, store result as polygon if partial.
  if (ann.type === 'ellipse') {
    const ellipsePoints = approximateEllipse(ann, 32);
    const clipped = clipPolygonToRect(ellipsePoints, w, h);
    if (!clipped.length) return null;
    // if clipping changed shape, store as polygon; else keep as ellipse
    const same = samePolygon(ellipsePoints, clipped);
    if (same) {
      // no change
      return ann;
    } else {
      return { type: 'polygon', points: clipped, label: ann.label || '' };
    }
  }

  // If unknown type
  return ann;
}

// Approximate an ellipse by N points
function approximateEllipse(ell, numSegments = 32) {
  const { x, y, radiusX, radiusY, rotation } = ell;
  const points = [];
  for (let i = 0; i < numSegments; i++) {
    const angle = (2 * Math.PI * i) / numSegments;
    // apply rotation
    const cosA = Math.cos(angle);
    const sinA = Math.sin(angle);
    let px = cosA * radiusX;
    let py = sinA * radiusY;
    // rotation
    const rot = (rotation * Math.PI) / 180;
    const rx = px * Math.cos(rot) - py * Math.sin(rot);
    const ry = px * Math.sin(rot) + py * Math.cos(rot);
    // translate
    points.push({ x: x + rx, y: y + ry });
  }
  return points;
}

// A simple polyline clip. It tries to do line-by-line segment clipping using the polygon approach
// but doesn't close the shape. This code is simplified. For more advanced partial-edge usage, 
// you'd carefully handle each segment.
function clipPolylineToRect(points, w, h) {
  if (points.length < 2) return [];

  let clippedSegments = [];
  // We'll clip each segment as if it were a 2-vertex polygon. Then combine results.
  for (let i = 0; i < points.length - 1; i++) {
    const segPoly = [points[i], points[i + 1]];
    const clipSeg = clipPolygonToRect(segPoly, w, h);
    if (clipSeg.length === 2) {
      // If segment fully inside or partially inside, we keep it
      // But watch for duplicates at junctions
      if (clippedSegments.length) {
        const last = clippedSegments[clippedSegments.length - 1];
        if (almostSamePoint(last, clipSeg[0])) {
          // just append the second
          clippedSegments.push(clipSeg[1]);
        } else {
          // add both
          clippedSegments.push(clipSeg[0], clipSeg[1]);
        }
      } else {
        clippedSegments.push(clipSeg[0], clipSeg[1]);
      }
    } else if (clipSeg.length === 1) {
      // Rare degenerate intersection exactly corner
      if (!clippedSegments.length) {
        clippedSegments.push(clipSeg[0]);
      } else {
        const last = clippedSegments[clippedSegments.length - 1];
        if (!almostSamePoint(last, clipSeg[0])) {
          clippedSegments.push(clipSeg[0]);
        }
      }
    }
    // if 0 => segment is out
  }

  return clippedSegments;
}

function almostSamePoint(a, b) {
  return Math.abs(a.x - b.x) < 0.0001 && Math.abs(a.y - b.y) < 0.0001;
}

// ----------------------------------------------------
// MAIN COMPONENT
// ----------------------------------------------------

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
  onDeleteAnnotation,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes (while drawing)
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // Points annotation
  const [tempPointPoints, setTempPointPoints] = useState([]);
  const [drawingPoint, setDrawingPoint] = useState(false);

  // For selecting shape to transform
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);
  const shapeRefs = useRef([]);

  // Track last click time for double-click (finish polygon/polyline)
  const lastClickTimeRef = useRef(0);
  const doubleClickThreshold = 250; // ms

  // For copy/paste
  const [copiedAnnotation, setCopiedAnnotation] = useState(null);

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Load image
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // Flatten array of points into [x1,y1,x2,y2,...]
  function flattenPoints(pts) {
    return pts.flatMap((p) => [p.x, p.y]);
  }

  // get pointer in local group coords
  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  // Create BBox
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const rawAnn = { type: 'bbox', ...newBox, label: '' };
    // Now clip if out of bounds at all
    if (konvaImg) {
      const clipped = clipAnnotationToImage(rawAnn, konvaImg.width, konvaImg.height);
      if (clipped) {
        onAnnotationsChange([...annotations, clipped]);
      }
    } else {
      onAnnotationsChange([...annotations, rawAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // Create Polygon
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const rawAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (konvaImg) {
        const clipped = clipAnnotationToImage(rawAnn, konvaImg.width, konvaImg.height);
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, rawAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // Create Polyline
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const rawAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (konvaImg) {
        const clipped = clipAnnotationToImage(rawAnn, konvaImg.width, konvaImg.height);
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, rawAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // Create multiple Points
  function addPointToPoints(pos) {
    setTempPointPoints((prev) => [...prev, pos]);
    setDrawingPoint(true);
  }
  function finalizePoint() {
    if (tempPointPoints.length > 0) {
      const rawAnn = { type: 'points', points: tempPointPoints, label: '' };
      if (konvaImg) {
        const clipped = clipAnnotationToImage(rawAnn, konvaImg.width, konvaImg.height);
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, rawAnn]);
      }
    }
    setTempPointPoints([]);
    setDrawingPoint(false);
    onFinishShape && onFinishShape();
  }

  // Create Ellipse
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    const rawAnn = { ...newEllipse };
    if (konvaImg) {
      const clipped = clipAnnotationToImage(rawAnn, konvaImg.width, konvaImg.height);
      if (clipped) {
        onAnnotationsChange([...annotations, clipped]);
      }
    } else {
      onAnnotationsChange([...annotations, rawAnn]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // Cancel shape on ESC
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
      setTempPointPoints([]);
      setDrawingPoint(false);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // Wheel Zoom
  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  // Right-click remove last *drawing* point
  function handleContextMenu(evt) {
    evt.evt.preventDefault();
    if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
      setTempPoints((prev) => prev.slice(0, -1));
    } else if (
      selectedTool === 'polyline' &&
      drawingPolyline &&
      tempPolyline.length > 0
    ) {
      setTempPolyline((prev) => prev.slice(0, -1));
    } else if (
      selectedTool === 'point' &&
      drawingPoint &&
      tempPointPoints.length > 0
    ) {
      setTempPointPoints((prev) => prev.slice(0, -1));
    }
  }

  // Mouse events
  function handleMouseDown(evt) {
    if (selectedTool === 'move') {
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    const now = Date.now();
    const delta = now - lastClickTimeRef.current;
    if (
      (selectedTool === 'polygon' ||
        selectedTool === 'polyline' ||
        selectedTool === 'point') &&
      delta < doubleClickThreshold
    ) {
      return; // double-click => handled in handleDblClick
    }
    lastClickTimeRef.current = now;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPointToPoints(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }
  }

  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }

  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }

  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    } else if (selectedTool === 'point' && drawingPoint) {
      finalizePoint();
    }
  }

  // Copy/Paste
  useEffect(() => {
    const handleKeyDown = (e) => {
      // Copy
      if (e.ctrlKey && (e.key === 'c' || e.key === 'C')) {
        if (selectedAnnotationIndex !== null) {
          e.preventDefault();
          setCopiedAnnotation(annotations[selectedAnnotationIndex]);
        }
      }
      // Paste
      if (e.ctrlKey && (e.key === 'v' || e.key === 'V')) {
        if (copiedAnnotation) {
          e.preventDefault();
          const newAnn = JSON.parse(JSON.stringify(copiedAnnotation));
          if (newAnn.x !== undefined && newAnn.y !== undefined) {
            newAnn.x += 10;
            newAnn.y += 10;
          } else if (newAnn.points) {
            newAnn.points = newAnn.points.map((pt) => ({
              x: pt.x + 10,
              y: pt.y + 10,
            }));
          }
          // Clip again so we don't paste partially outside
          if (konvaImg) {
            const clipped = clipAnnotationToImage(newAnn, konvaImg.width, konvaImg.height);
            if (clipped) {
              onAnnotationsChange([...annotations, clipped]);
            }
          } else {
            onAnnotationsChange([...annotations, newAnn]);
          }
        }
      }

      // Remove last "drawing" point if user is in the middle of creating polygon, polyline, or points
      if (e.key === 'Backspace' || e.key === 'Delete') {
        if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
          e.preventDefault();
          setTempPoints((prev) => prev.slice(0, -1));
        } else if (
          selectedTool === 'polyline' &&
          drawingPolyline &&
          tempPolyline.length > 0
        ) {
          e.preventDefault();
          setTempPolyline((prev) => prev.slice(0, -1));
        } else if (
          selectedTool === 'point' &&
          drawingPoint &&
          tempPointPoints.length > 0
        ) {
          e.preventDefault();
          setTempPointPoints((prev) => prev.slice(0, -1));
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [
    annotations,
    onAnnotationsChange,
    selectedAnnotationIndex,
    copiedAnnotation,
    selectedTool,
    drawingPolygon,
    drawingPolyline,
    drawingPoint,
    tempPoints,
    tempPolyline,
    tempPointPoints,
    konvaImg,
  ]);

  // Draggable logic for entire shapes
  const handleBBoxDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    // after drag, clip
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[index], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[index], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePointDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[index], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePolylineDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[index], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePolygonDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[index], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  function handleRemoveVertex(annIndex, vertexIndex) {
    const updated = [...annotations];
    const ann = { ...updated[annIndex] };
    const shapePoints = [...ann.points];
    shapePoints.splice(vertexIndex, 1);

    if (ann.type === 'polygon' && shapePoints.length < 3) {
      updated.splice(annIndex, 1);
    } else if (ann.type === 'polyline' && shapePoints.length < 2) {
      updated.splice(annIndex, 1);
    } else if (ann.type === 'points' && shapePoints.length < 1) {
      updated.splice(annIndex, 1);
    } else {
      ann.points = shapePoints;
      updated[annIndex] = ann;
    }

    onAnnotationsChange(updated);
  }

  function handleInsertVertex(annIndex, vertexIndex) {
    const updated = [...annotations];
    const ann = { ...updated[annIndex] };

    if (ann.type !== 'polygon' && ann.type !== 'polyline') return;
    const shapePoints = [...ann.points];
    const length = shapePoints.length;
    if (length < 2) return;

    let nextIndex;
    if (ann.type === 'polygon') {
      nextIndex = (vertexIndex + 1) % length;
    } else {
      if (vertexIndex === length - 1) {
        return;
      }
      nextIndex = vertexIndex + 1;
    }

    const currentPt = shapePoints[vertexIndex];
    const nextPt = shapePoints[nextIndex];
    const midX = (currentPt.x + nextPt.x) / 2;
    const midY = (currentPt.y + nextPt.y) / 2;

    shapePoints.splice(vertexIndex + 1, 0, { x: midX, y: midY });
    ann.points = shapePoints;
    updated[annIndex] = ann;
    onAnnotationsChange(updated);
  }

  const handleVertexDragEnd = (annIndex, vertexIndex, e) => {
    e.cancelBubble = true;
    const { x, y } = e.target.position();
    const updated = [...annotations];
    const shapePoints = [...updated[annIndex].points];
    shapePoints[vertexIndex] = { x, y };
    updated[annIndex] = { ...updated[annIndex], points: shapePoints };
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updated[annIndex], konvaImg.width, konvaImg.height);
      if (!clipped) {
        updated.splice(annIndex, 1);
      } else {
        updated[annIndex] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  // Transformer (only for bbox & ellipse)
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }
    const node = shapeRefs.current[selectedAnnotationIndex];
    if (node) {
      tr.nodes([node]);
      tr.getLayer().batchDraw();
    } else {
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations]);

  const handleTransformEnd = () => {
    if (selectedAnnotationIndex == null) return;
    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;

    const ann = annotations[selectedAnnotationIndex];
    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();

    let updatedAnn = { ...ann };

    switch (ann.type) {
      case 'bbox': {
        const newWidth = shapeNode.width() * scaleX;
        const newHeight = shapeNode.height() * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.width = newWidth;
        updatedAnn.height = newHeight;
        break;
      }
      case 'ellipse': {
        const newRadiusX = (shapeNode.width() / 2) * scaleX;
        const newRadiusY = (shapeNode.height() / 2) * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.radiusX = newRadiusX;
        updatedAnn.radiusY = newRadiusY;
        break;
      }
      default:
        break;
    }

    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);

    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;

    // Now clip
    if (konvaImg) {
      const clipped = clipAnnotationToImage(updatedAnn, konvaImg.width, konvaImg.height);
      if (!clipped) {
        updatedAll.splice(selectedAnnotationIndex, 1);
      } else {
        updatedAll[selectedAnnotationIndex] = clipped;
      }
    }
    onAnnotationsChange(updatedAll);
  };

  // Minimal bounding box for labeling "Delete"
  function shapeBoundingBox(ann) {
    // We'll use the polygon bounding box or direct for rectangle
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.points) {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  }

  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
        onContextMenu={handleContextMenu}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <React.Fragment key={i}>
                    <Rect
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleBBoxDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <React.Fragment key={i}>
                    <Ellipse
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      radiusX={ann.radiusX}
                      radiusY={ann.radiusY}
                      rotation={ann.rotation || 0}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleEllipseDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'point') {
                return (
                  <React.Fragment key={i}>
                    <Circle
                      x={ann.x}
                      y={ann.y}
                      radius={6 / scale}
                      fill={activeLabelColor}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePointDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polyline') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        closed={false}
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={activeLabelColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                          onClick={(ev) => {
                            ev.cancelBubble = true;
                            handleInsertVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={activeLabelColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polygon') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolygonDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        fill={fillColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        closed
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={activeLabelColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                          onClick={(ev) => {
                            ev.cancelBubble = true;
                            handleInsertVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={activeLabelColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'points') {
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={6 / scale}
                          fill={activeLabelColor}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                        />
                      ))}
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && selectedTool === 'polygon' && (
              <>
                {tempPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...tempPoints, tempPoints[0]])}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {tempPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && selectedTool === 'polyline' && (
              <>
                {tempPolyline.length > 1 && (
                  <Line
                    points={flattenPoints(tempPolyline)}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed={false}
                  />
                )}
                {tempPolyline.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={newEllipse.rotation}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Points */}
            {drawingPoint && selectedTool === 'point' && (
              <>
                {tempPointPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}
          </Group>

          {/* Transformer (only for bbox & ellipse) */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
}

// A small Konva Label to let user delete a selected annotation
function DeleteLabel({ annotation, scale, shapeBoundingBox, onDelete }) {
  const box = shapeBoundingBox(annotation);
  if (!box) return null;
  const xPos = box.x1;
  const yPos = box.y1 - 20 / scale;

  return (
    <Label
      x={xPos}
      y={yPos}
      onClick={(e) => {
        e.cancelBubble = true;
        onDelete();
      }}
      scaleX={1 / scale}
      scaleY={1 / scale}
    >
      <Tag fill="red" opacity={0.8} cornerRadius={4} />
      <Text text="Delete" fill="#fff" padding={5} fontSize={14} />
    </Label>
  );
}
